<script setup lang="ts">
import { computed,onMounted,ref } from 'vue'; import AppShell from '../components/AppShell.vue'; import { classroomApi } from '../api/classroomApi'; import { formatDateTime,statusText } from '../utils/display'; import type { ClassroomSession } from '../types'
const sessions=ref<ClassroomSession[]>([]),loading=ref(true),query=ref(''),error=ref('')
const reports=computed(()=>sessions.value.filter(x=>x.status==='ended'&&(!query.value||(x.courseTitle||'音乐课堂').includes(query.value))))
async function load(){loading.value=true;try{sessions.value=await classroomApi.listActiveSessions()}catch(e){error.value=e instanceof Error?e.message:'加载报告失败'}finally{loading.value=false}}
onMounted(load)
</script>
<template><AppShell><div class="page-heading"><div><p class="eyebrow">数据报告</p><h1>课后教学报告</h1><p>这里仅展示已结束的课堂，用于复盘学生参与和活动完成情况。</p></div><button class="button" @click="load">刷新报告</button></div><div class="report-summary"><div class="card"><strong>{{ reports.length }}</strong><span>已结束课堂</span></div><div class="card"><strong>{{ reports.reduce((sum,item)=>sum+item.nodeStates.length,0) }}</strong><span>已实施活动</span></div><div class="card"><strong>课后</strong><span>报告统计阶段</span></div></div><div class="filter-bar"><input v-model="query" placeholder="搜索课程名称" aria-label="搜索课程名称"></div><p v-if="error" class="error">{{ error }}</p><div class="report-list"><article v-for="session in reports" :key="session.id" class="card"><div><span class="status-pill ended">{{ statusText(session.status) }}</span><h2>{{ session.courseTitle||'音乐课堂' }}</h2><p>{{ formatDateTime(session.endedAt||session.startedAt) }} · {{ session.nodeStates.length }} 个课堂环节</p></div><RouterLink class="button primary-soft" :to="`/classroom/${session.id}/report`">查看报告 →</RouterLink></article><div v-if="!reports.length" class="empty-inline">{{ loading?'正在加载报告…':'暂无已结束的课堂报告' }}</div></div></AppShell></template>
